const fs = require("fs");
const path = require("path");

const PATCH_LINE =
  'import{createRequire}from"module";try{createRequire(import.meta.url)("./cursor-rtl-loader.cjs")}catch(e){console.error("[Cursor RTL] error loading ./cursor-rtl-loader.cjs: ", e)}';
const PATCH_MARKER = "cursor-rtl-loader.cjs";
const BACKUP_PREFIX = "main.js.rtl-backup-";

const outDir = path.join(
  process.env.LOCALAPPDATA,
  "Programs",
  "cursor",
  "resources",
  "app",
  "out"
);
const mainJsPath = path.join(outDir, "main.js");
const extPath = path.join(
  process.env.USERPROFILE,
  ".cursor",
  "extensions",
  "motcke.cursor-rtl-1.1.8"
);
const loaderSrc = path.join(extPath, "resources", "cursor-rtl-loader.cjs");
const loaderDest = path.join(outDir, "cursor-rtl-loader.cjs");

function formatTimestamp() {
  const now = new Date();
  const pad = (n) => String(n).padStart(2, "0");
  return (
    now.getFullYear().toString() +
    pad(now.getMonth() + 1) +
    pad(now.getDate()) +
    "T" +
    pad(now.getHours()) +
    pad(now.getMinutes()) +
    pad(now.getSeconds())
  );
}

function isPatched() {
  return fs.readFileSync(mainJsPath, "utf-8").includes(PATCH_LINE);
}

function applyPatch() {
  const content = fs.readFileSync(mainJsPath, "utf-8");
  if (!content.includes("Copyright (C) Microsoft Corporation")) {
    throw new Error("main.js signature not found — unsupported Cursor version?");
  }
  if (content.includes(PATCH_LINE)) {
    console.log("PATCH: already applied");
    return;
  }

  const backupPath = path.join(outDir, BACKUP_PREFIX + formatTimestamp());
  fs.copyFileSync(mainJsPath, backupPath);
  console.log("BACKUP:", backupPath);

  const lines = content.split("\n");
  const existingIndex = lines.findIndex((line) =>
    line.startsWith("import{createRequire")
  );
  if (existingIndex !== -1) {
    lines[existingIndex] = PATCH_LINE;
    fs.writeFileSync(mainJsPath, lines.join("\n"), "utf-8");
  } else {
    const copyrightEnd = content.indexOf("*/");
    if (copyrightEnd === -1) throw new Error("copyright block not found");
    const insertPos = copyrightEnd + 2;
    const patched =
      content.substring(0, insertPos) +
      "\n" +
      PATCH_LINE +
      content.substring(insertPos);
    fs.writeFileSync(mainJsPath, patched, "utf-8");
  }
  console.log("PATCH: applied");
}

function copyLoader() {
  if (!fs.existsSync(loaderSrc)) {
    throw new Error("loader not found: " + loaderSrc);
  }
  fs.copyFileSync(loaderSrc, loaderDest);
  console.log("LOADER:", loaderDest);
}

try {
  if (!fs.existsSync(mainJsPath)) throw new Error("main.js missing: " + mainJsPath);
  copyLoader();
  applyPatch();
  console.log("OK: RTL enabled. Restart Cursor completely.");
  process.exit(0);
} catch (err) {
  console.error("FAIL:", err.message);
  process.exit(1);
}
